const request = $input.first().json;
const payload = request.body || request;
const headers = request.headers || {};

const supportedEvents = {
  'email.opened': 'email_opened',
  'email.clicked': 'email_clicked'
};

const rawEventType = payload.type || payload.event || '';
const mappedEventType = supportedEvents[rawEventType];
if (!mappedEventType) {
  return [{ json: { _skip: true, status: 'ignored', reason: 'unsupported_event', raw_event_type: rawEventType || null } }];
}

const resendMessageId = payload.data?.email_id || payload.data?.emailId || payload.data?.id || null;
if (!resendMessageId) {
  return [{ json: { _skip: true, status: 'ignored', reason: 'missing_resend_message_id', raw_event_type: rawEventType } }];
}

const externalEventId = headers['svix-id'] || headers['webhook-id'] || null;
const baseUrl = $env.SUPABASE_URL;
const serviceKey = $env.SUPABASE_SERVICE_ROLE_KEY;
const supabaseHeaders = {
  apikey: serviceKey,
  Authorization: `Bearer ${serviceKey}`
};

if (externalEventId) {
  const duplicateRes = await fetch(`${baseUrl}/rest/v1/activity_log?select=id&external_event_id=eq.${encodeURIComponent(externalEventId)}&limit=1`, {
    headers: supabaseHeaders
  });
  const duplicateRows = await duplicateRes.json();
  if (Array.isArray(duplicateRows) && duplicateRows.length > 0) {
    return [{ json: { _skip: true, status: 'duplicate', reason: 'external_event_id_exists', external_event_id: externalEventId } }];
  }
}

const emailSendRes = await fetch(`${baseUrl}/rest/v1/activity_log?select=lead_id,company_id,resend_message_id&event_type=eq.ai_auto_reply_sent&resend_message_id=eq.${encodeURIComponent(resendMessageId)}&order=created_at.desc&limit=1`, {
  headers: supabaseHeaders
});
const emailSendRows = await emailSendRes.json();
if (!Array.isArray(emailSendRows) || emailSendRows.length === 0) {
  return [{ json: { _skip: true, status: 'ignored', reason: 'matching_email_not_found', resend_message_id: resendMessageId } }];
}

const sourceRow = emailSendRows[0];
const occurredAt = payload.created_at || payload.data?.created_at || payload.data?.clicked_at || payload.data?.opened_at || new Date().toISOString();

return [{
  json: {
    _skip: false,
    status: 'ready',
    lead_id: sourceRow.lead_id,
    company_id: sourceRow.company_id,
    event_type: mappedEventType,
    resend_message_id: resendMessageId,
    external_event_id: externalEventId,
    occurred_at: occurredAt,
    metadata: {
      channel: 'email',
      raw_event_type: rawEventType,
      recipient: payload.data?.to || payload.data?.email || null,
      link: payload.data?.url || payload.data?.link || null,
      user_agent: payload.data?.user_agent || null,
      ip_address: payload.data?.ip_address || null,
      resend_payload_id: payload.data?.id || null
    }
  }
}];
